// SEC_CM: REG.BUS.INTEGRITY
// SEC_CM: CTRL.CONFIG.REGWEN
// SEC_CM: DATA_REGIONS.CONFIG.REGWEN
// SEC_CM: INFO_PAGE.CONFIG.REGWEN
rram_ctrl_core_reg_top u_reg_core (
  .clk_i,
  .rst_ni,
  .tl_i      (core_tl_i),
  .tl_o      (core_tl_o),
  .tl_win_o  (tl_win_h2d),
  .tl_win_i  (tl_win_d2h),
  .reg2hw    (reg2hw),
  .hw2reg    (hw2reg),
  .intg_err_o(intg_err)
);

// The write path also needs an lc gate to error back when the RRAM is disabled.
// This is because tlul_adapter_sram does not actually have a way of signaling
// write errors, only read errors.
// SEC_CM: WR_TL_LC_GATE.FSM.SPARSE
tlul_lc_gate u_wr_tl_gate (
  .clk_i,
  .rst_ni,
  .tl_h2d_i      (tl_win_h2d[0]),
  .tl_d2h_o      (tl_win_d2h[0]),
  .tl_h2d_o      (wr_tl_h2d),
  .tl_d2h_i      (wr_tl_d2h),
  .flush_req_i   ('0),
  .flush_ack_o   (),
  .resp_pending_o(),
  .lc_en_i       (lc_ctrl_pkg::mubi4_to_lc_inv(rram_disable[WrFifoIdx])),
  .err_o         (tl_wr_gate_intg_err)
);

///////////////////////
// MEMORY PROTECTION //
///////////////////////
// Convert all mp rules to an array
rram_ctrl_region_cfg u_rram_ctrl_region_cfg (
  .clk_i,
  .rst_ni,
  .lc_creator_seed_sw_rw_en_i,
  .lc_owner_seed_sw_rw_en_i,
  .lc_iso_part_sw_wr_en_i,
  .lc_iso_part_sw_rd_en_i,
  .region_i        (reg2hw.mp_region),
  .region_cfg_i    (reg2hw.mp_region_cfg),
  .default_cfg_i   (reg2hw.default_region),
  .info_page_cfg_i (reg2hw.info_page_cfg),
  .region_cfgs_o   (region_cfgs),
  .info_page_cfgs_o(info_page_cfgs)
);

// Synchronize enables into local domain
prim_lc_sync #(
  .NumCopies(1)
) u_lc_creator_seed_sw_rw_en_sync (
  .clk_i,
  .rst_ni,
  .lc_en_i(lc_creator_seed_sw_rw_en_i),
  .lc_en_o({lc_creator_seed_sw_rw_en})
);

// without this buffer host_gnt_err will get optimized away
prim_buf #(
  .Width($bits(rram_part_e))
) u_prim_buf_muxed_part (
  .in_i ({muxed_part}),
  .out_o({muxed_part_buf})
);

/////////////////////////
// Read-buf dependency //
/////////////////////////
rram_phy_rd_buf_dep #(
  .Depth(NumOutstandingRdReq)
) u_rram_phy_rd_buf_dep (
  .clk_i,
  .rst_ni,
  .fifo_wr_i   (meta_fifo_req & meta_fifo_rdy),
  .fifo_rd_i   (meta_fifo_pop & meta_fifo_valid),
  .wr_buf_i    (meta_d.buf_sel),
  .rd_buf_i    (meta_q.buf_sel),
  .dependency_o(buf_dependency)
);

//////////////////////////
// RRAM shadow requests //
//////////////////////////
// Select from all valid buffers one to verify
prim_arbiter_tree #(
  .N(NumRdBuf),
  .DW(2),
  .EnDataPort(1'b0)
) u_buf_sel_verify (
  .clk_i,
  .rst_ni,
  .req_chk_i(1'b0),
  .req_i    (buf_valid),
  .data_i   (dummy_data),
  .gnt_o    (buf_to_verify),
  .idx_o    (),
  .valid_o  (),
  .data_o   (),
  .ready_i  (1'b1)
);

/////////////////
// RRAM Access //
/////////////////
prim_arbiter_tree #(
  .N(2),
  .DW(1),
  .EnDataPort(1'b0)
) u_req_sel (
  .clk_i,
  .rst_ni,
  .req_chk_i(1'b0),
  .req_i    ({shadow_rd_req, rd_req}),
  .data_i   ('{default: '0}),
  .gnt_o    ({shadow_rd_gnt, rd_gnt}),
  .idx_o    (),
  .valid_o  (rd_req_o),
  .data_o   (),
  .ready_i  (1'b1)
);

prim_secded_inv_28_22_enc u_cmd_intg_req_gen (
  .data_i({ecc_en_i, descramble_en_i, addr_i, part_i}),
  .data_o({meta_d.cmd_intg, unused_cmd_data0})
);

// Command integrity of response
prim_secded_inv_28_22_enc u_cmd_intg_rsp_gen (
  .data_i({rd_buf_ecc_en, rd_buf_descramble_en, rd_buf_addr, meta_q_buf.word_sel, rd_buf_part}),
  .data_o({cmd_rsp_intg, unused_cmd_data1})
);

// use the tlul integrity module directly for bus integrity
// SEC_CM: MEM.BUS.INTEGRITY
tlul_data_integ_dec u_data_intg_chk (
  .data_intg_i(data_i),
  .data_err_o (data_intg_err_d)
);
